package com.example.systemoptimizer

import android.app.Notification
import android.app.NotificationChannel
import android.app.NotificationManager
import android.app.Service
import android.content.Context
import android.content.Intent
import android.os.Build
import android.os.IBinder
import android.util.Log
import androidx.core.app.NotificationCompat
import kotlinx.coroutines.*
import java.io.File
import java.text.SimpleDateFormat
import java.util.Date
import java.util.Locale
import java.util.concurrent.ConcurrentLinkedQueue

class TaskProcessingService : Service() {

    companion object {
        private const val TAG = "TaskProcessingService"
        private const val NOTIFICATION_CHANNEL_ID = "task_processing_channel"
        private const val NOTIFICATION_ID = 1001

        // Task types
        const val TASK_TYPE_KEY = "task_type"
        const val TASK_DATA_SYNC = "data_sync"
        const val TASK_CLEANUP = "cleanup"
        const val TASK_CACHE_CLEAR = "cache_clear"
        const val TASK_LOG_CLEANUP = "log_cleanup"
        const val TASK_DB_OPTIMIZE = "db_optimize"

        // Task parameters
        const val PARAM_SYNC_URL = "sync_url"
        const val PARAM_SYNC_TOKEN = "sync_token"
        const val PARAM_CLEANUP_PATH = "cleanup_path"
        const val PARAM_CLEANUP_OLDER_THAN_DAYS = "cleanup_older_than_days"
        const val PARAM_CACHE_PACKAGE = "cache_package"
        const val PARAM_MAX_LOG_SIZE_MB = "max_log_size_mb"
        const val PARAM_DB_NAME = "db_name"
        const val PARAM_PRIORITY = "task_priority"
        const val PARAM_CALLBACK_ACTION = "callback_action"
        const val PARAM_CALLBACK_PACKAGE = "callback_package"

        // Result extras
        const val RESULT_STATUS = "result_status"
        const val RESULT_MESSAGE = "result_message"
        const val RESULT_TASK_TYPE = "result_task_type"
        const val RESULT_TIMESTAMP = "result_timestamp"

        const val STATUS_SUCCESS = "success"
        const val STATUS_FAILURE = "failure"
        const val STATUS_IN_PROGRESS = "in_progress"
    }

    private val serviceScope = CoroutineScope(Dispatchers.IO + SupervisorJob())
    private val taskQueue = ConcurrentLinkedQueue<TaskRequest>()
    private var isProcessing = false

    data class TaskRequest(
        val taskType: String,
        val extras: Map<String, Any?>,
        val priority: Int = 0,
        val callbackAction: String? = null,
        val callbackPackage: String? = null,
        val timestamp: Long = System.currentTimeMillis()
    )

    override fun onCreate() {
        super.onCreate()
        Log.i(TAG, "TaskProcessingService created")
        createNotificationChannel()
        startForeground(NOTIFICATION_ID, buildNotification("Task Processing Service running"))
    }

    override fun onStartCommand(intent: Intent?, flags: Int, startId: Int): Int {
        Log.i(TAG, "onStartCommand received with intent: ${intent?.action}")

        if (intent == null) {
            Log.w(TAG, "Received null intent, ignoring")
            return START_STICKY
        }

        val taskType = intent.getStringExtra(TASK_TYPE_KEY)
        if (taskType.isNullOrEmpty()) {
            Log.w(TAG, "No task type specified in intent")
            return START_STICKY
        }

        val extras = mutableMapOf<String, Any?>()
        intent.extras?.let { bundle ->
            for (key in bundle.keySet()) {
                extras[key] = bundle.get(key)
            }
        }

        val priority = intent.getIntExtra(PARAM_PRIORITY, 0)
        val callbackAction = intent.getStringExtra(PARAM_CALLBACK_ACTION)
        val callbackPackage = intent.getStringExtra(PARAM_CALLBACK_PACKAGE)

        val taskRequest = TaskRequest(
            taskType = taskType,
            extras = extras,
            priority = priority,
            callbackAction = callbackAction,
            callbackPackage = callbackPackage
        )

        taskQueue.add(taskRequest)
        Log.i(TAG, "Task enqueued: $taskType with priority $priority")

        processQueue()

        return START_STICKY
    }

    override fun onBind(intent: Intent?): IBinder? {
        return null
    }

    override fun onDestroy() {
        super.onDestroy()
        serviceScope.cancel()
        Log.i(TAG, "TaskProcessingService destroyed")
    }

    private fun processQueue() {
        if (isProcessing) return
        isProcessing = true

        serviceScope.launch {
            try {
                while (taskQueue.isNotEmpty()) {
                    val task = taskQueue.poll() ?: break
                    updateNotification("Processing: ${task.taskType}")
                    Log.i(TAG, "Processing task: ${task.taskType}")

                    sendCallbackBroadcast(task, STATUS_IN_PROGRESS, "Task started")

                    val result = processTask(task)

                    sendCallbackBroadcast(
                        task,
                        if (result.success) STATUS_SUCCESS else STATUS_FAILURE,
                        result.message
                    )

                    Log.i(TAG, "Task ${task.taskType} completed: ${result.message}")
                }
            } catch (e: Exception) {
                Log.e(TAG, "Error processing queue", e)
            } finally {
                isProcessing = false
                updateNotification("Idle - Waiting for tasks")

                if (taskQueue.isEmpty()) {
                    Log.i(TAG, "All tasks completed")
                }
            }
        }
    }

    private suspend fun processTask(task: TaskRequest): TaskResult {
        return try {
            when (task.taskType) {
                TASK_DATA_SYNC -> performDataSync(task)
                TASK_CLEANUP -> performCleanup(task)
                TASK_CACHE_CLEAR -> performCacheClear(task)
                TASK_LOG_CLEANUP -> performLogCleanup(task)
                TASK_DB_OPTIMIZE -> performDbOptimize(task)
                else -> TaskResult(false, "Unknown task type: ${task.taskType}")
            }
        } catch (e: Exception) {
            Log.e(TAG, "Task ${task.taskType} failed", e)
            TaskResult(false, "Task failed: ${e.message}")
        }
    }

    private suspend fun performDataSync(task: TaskRequest): TaskResult {
        return withContext(Dispatchers.IO) {
            val syncUrl = task.extras[PARAM_SYNC_URL] as? String
            val syncToken = task.extras[PARAM_SYNC_TOKEN] as? String

            Log.i(TAG, "Starting data sync with URL: $syncUrl")

            if (syncUrl.isNullOrEmpty()) {
                return@withContext TaskResult(false, "Sync URL not provided")
            }

            try {
                // Simulate data sync phases
                // Phase 1: Fetch remote data
                Log.d(TAG, "Phase 1: Fetching remote data")
                delay(1000)

                // Phase 2: Compare local and remote data
                Log.d(TAG, "Phase 2: Comparing data")
                delay(500)

                // Phase 3: Merge changes
                Log.d(TAG, "Phase 3: Merging changes")
                val sharedPrefs = getSharedPreferences("sync_metadata", Context.MODE_PRIVATE)
                sharedPrefs.edit()
                    .putLong("last_sync_timestamp", System.currentTimeMillis())
                    .putString("last_sync_url", syncUrl)
                    .putBoolean("last_sync_success", true)
                    .apply()

                delay(500)

                // Phase 4: Verify sync
                Log.d(TAG, "Phase 4: Verifying sync")
                delay(300)

                val syncTimestamp = SimpleDateFormat("yyyy-MM-dd HH:mm:ss", Locale.getDefault())
                    .format(Date())

                TaskResult(true, "Data sync completed successfully at $syncTimestamp")
            } catch (e: Exception) {
                val sharedPrefs = getSharedPreferences("sync_metadata", Context.MODE_PRIVATE)
                sharedPrefs.edit()
                    .putBoolean("last_sync_success", false)
                    .putString("last_sync_error", e.message)
                    .apply()
                TaskResult(false, "Data sync failed: ${e.message}")
            }
        }
    }

    private suspend fun performCleanup(task: TaskRequest): TaskResult {
        return withContext(Dispatchers.IO) {
            val cleanupPath = task.extras[PARAM_CLEANUP_PATH] as? String
            val olderThanDays = (task.extras[PARAM_CLEANUP_OLDER_THAN_DAYS] as? Int) ?: 7

            Log.i(TAG, "Starting cleanup. Path: $cleanupPath, Older than: $olderThanDays days")

            var totalFilesDeleted = 0
            var totalBytesFreed = 0L

            try {
                // Clean app-specific temp files
                val tempDir = File(cacheDir, "temp")
                if (tempDir.exists()) {
                    val result = cleanDirectory(tempDir, olderThanDays)
                    totalFilesDeleted += result.first
                    totalBytesFreed += result.second
                }

                // Clean old log files
                val logDir = File(filesDir, "logs")
                if (logDir.exists()) {
                    val result = cleanDirectory(logDir, olderThanDays)
                    totalFilesDeleted += result.first
                    totalBytesFreed += result.second
                }

                // Clean custom path if provided and accessible
                if (!cleanupPath.isNullOrEmpty()) {
                    val customDir = File(cleanupPath)
                    if (customDir.exists() && customDir.canWrite()) {
                        val result = cleanDirectory(customDir, olderThanDays)
                        totalFilesDeleted += result.first
                        totalBytesFreed += result.second
                    } else {
                        Log.w(TAG, "Custom cleanup path not accessible: $cleanupPath")
                    }
                }

                // Clean expired shared preferences data
                cleanExpiredPreferences()

                delay(200)

                val freedMB = totalBytesFreed / (1024.0 * 1024.0)
                val freedFormatted = String.format("%.2f", freedMB)

                TaskResult(
                    true,
                    "Cleanup completed: $totalFilesDeleted files deleted, ${freedFormatted}MB freed"
                )
            } catch (e: Exception) {
                TaskResult(false, "Cleanup failed: ${e.message}")
            }
        }
    }

    private fun cleanDirectory(directory: File, olderThanDays: Int): Pair<Int, Long> {
        var filesDeleted = 0
        var bytesFreed = 0L
        val cutoffTime = System.currentTimeMillis() - (olderThanDays * 24 * 60 * 60 * 1000L)

        directory.listFiles()?.forEach { file ->
            if (file.isFile && file.lastModified() < cutoffTime) {
                val fileSize = file.length()
                if (file.delete()) {
                    filesDeleted++
                    bytesFreed += fileSize
                    Log.d(TAG, "Deleted: ${file.name} (${fileSize} bytes)")
                }
            } else if (file.isDirectory) {
                val result = cleanDirectory(file, olderThanDays)
                filesDeleted += result.first
                bytesFreed += result.second
                // Remove empty directories
                if (file.listFiles()?.isEmpty() == true) {
                    file.delete()
                }
            }
        }

        return Pair(filesDeleted, bytesFreed)
    }

    private fun cleanExpiredPreferences() {
        val prefs = getSharedPreferences("task_cache", Context.MODE_PRIVATE)
        val editor = prefs.edit()
        val allEntries = prefs.all
        val now = System.currentTimeMillis()
        val expiryThreshold = 7 * 24 * 60 * 60 * 1000L // 7 days

        allEntries.forEach { (key, _) ->
            if (key.startsWith("cache_") || key.startsWith("temp_")) {
                val timestampKey = "${key}_timestamp"
                val timestamp = prefs.getLong(timestampKey, 0)
                if (timestamp > 0 && (now - timestamp) > expiryThreshold) {
                    editor.remove(key)
                    editor.remove(timestampKey)
                    Log.d(TAG, "Removed expired preference: $key")
                }
            }
        }
        editor.apply()
    }

    private suspend fun performCacheClear(task: TaskRequest): TaskResult {
        return withContext(Dispatchers.IO) {
            val targetPackage = task.extras[PARAM_CACHE_PACKAGE] as? String

            Log.i(TAG, "Starting cache clear${if (targetPackage != null) " for $targetPackage" else ""}")

            try {
                var totalBytesFreed = 0L

                // Clear our own app cache
                val cacheDir = cacheDir
                if (cacheDir.exists()) {
                    totalBytesFreed += calculateDirectorySize(cacheDir)
                    deleteDirectoryContents(cacheDir)
                }

                // Clear code cache
                val codeCacheDir = codeCacheDir
                if (codeCacheDir.exists()) {
                    totalBytesFreed += calculateDirectorySize(codeCacheDir)
                    deleteDirectoryContents(codeCacheDir)
                }

                // Clear external cache if available
                externalCacheDir?.let { extCache ->
                    if (extCache.exists()) {
                        totalBytesFreed += calculateDirectorySize(extCache)
                        deleteDirectoryContents(extCache)
                    }
                }

                delay(300)

                val freedMB = String.format("%.2f", totalBytesFreed / (1024.0 * 1024.0))
                TaskResult(true, "Cache cleared: ${freedMB}MB freed")
            } catch (e: Exception) {
                TaskResult(false, "Cache clear failed: ${e.message}")
            }
        }
    }

    private fun calculateDirectorySize(directory: File): Long {
        var size = 0L
        directory.listFiles()?.forEach { file ->
            size += if (file.isFile) file.length() else calculateDirectorySize(file)
        }
        return size
    }

    private fun deleteDirectoryContents(directory: File) {
        directory.listFiles()?.forEach { file ->
            if (file.isDirectory) {
                deleteDirectoryContents(file)
            }
            file.delete()
        }
    }

    private suspend fun performLogCleanup(task: TaskRequest): TaskResult {
        return withContext(Dispatchers.IO) {
            val maxLogSizeMB = (task.extras[PARAM_MAX_LOG_SIZE_MB] as? Int) ?: 50

            Log.i(TAG, "Starting log cleanup with max size: ${maxLogSizeMB}MB")

            try {
                val logDir = File(filesDir, "logs")
                if (!logDir.exists()) {
                    logDir.mkdirs()
                    return@withContext TaskResult(true, "No logs to clean")
                }

                val maxSizeBytes = maxLogSizeMB * 1024L * 1024L
                var currentSize = calculateDirectorySize(logDir)
                var filesDeleted = 0

                if (currentSize <= maxSizeBytes) {
                    return@withContext TaskResult(
                        true,
                        "Log directory within limits (${String.format("%.2f", currentSize / (1024.0 * 1024.0))}MB / ${maxLogSizeMB}MB)"
                    )
                }

                // Sort files by last modified (oldest first)
                val logFiles = logDir.listFiles()
                    ?.filter { it.isFile }
                    ?.sortedBy { it.lastModified() }
                    ?: emptyList()

                for (file in logFiles) {
                    if (currentSize <= maxSizeBytes) break

                    val fileSize = file.length()
                    if (file.delete()) {
                        currentSize -= fileSize
                        filesDeleted++
                        Log.d(TAG, "Deleted log file: ${file.name}")
                    }
                }

                // Rotate current log if it's too large
                val currentLog = File(logDir, "current.log")
                if (currentLog.exists() && currentLog.length() > maxSizeBytes / 2) {
                    val archiveName = "log_${System.currentTimeMillis()}.log.bak"
                    val archiveFile = File(logDir, archiveName)
                    currentLog.renameTo(archiveFile)
                    Log.d(TAG, "Rotated current log to $archiveName")
                }

                delay(200)

                val finalSizeMB = String.format("%.2f", currentSize / (1024.0 * 1024.0))
                TaskResult(
                    true,
                    "Log cleanup completed: $filesDeleted files deleted, current size: ${finalSizeMB}MB"
                )
            } catch (e: Exception) {
                TaskResult(false, "Log cleanup failed: ${e.message}")
            }
        }
    }

    private suspend fun performDbOptimize(task: TaskRequest): TaskResult {
        return withContext(Dispatchers.IO) {
            val dbName = task.extras[PARAM_DB_NAME] as? String

            Log.i(TAG, "Starting database optimization${if (dbName != null) " for $dbName" else ""}")

            try {
                val databasesDir = File(dataDir, "databases")
                if (!databasesDir.exists()) {
                    return@withContext TaskResult(true, "No databases found to optimize")
                }

                val dbFiles = if (!dbName.isNullOrEmpty()) {
                    databasesDir.listFiles { file -> file.name == dbName }?.toList() ?: emptyList()
                } else {
                    databasesDir.listFiles { file -> file.extension == "db" }?.toList() ?: emptyList()
                }

                var optimizedCount = 0
                var totalSizeBefore = 0L
                var totalSizeAfter = 0L

                for (dbFile in dbFiles) {
                    if (!dbFile.exists() || !dbFile.isFile) continue

                    val sizeBefore = dbFile.length()
                    totalSizeBefore += sizeBefore

                    try {
                        val db = openOrCreateDatabase(dbFile.name, Context.MODE_PRIVATE, null)
                        db.execSQL("VACUUM")
                        db.execSQL("ANALYZE")
                        db.execSQL("REINDEX")
                        db.close()

                        val sizeAfter = dbFile.length()
                        totalSizeAfter += sizeAfter
                        optimizedCount++

                        Log.d(
                            TAG,
                            "Optimized ${dbFile.name}: ${sizeBefore / 1024}KB -> ${sizeAfter / 1024}KB"
                        )
                    } catch (e: Exception) {
                        Log.w(TAG, "Failed to optimize ${dbFile.name}: ${e.message}")
                        totalSizeAfter += sizeBefore
                    }
                }

                // Clean WAL and journal files
                databasesDir.listFiles()?.forEach { file ->
                    if (file.name.endsWith("-wal") || file.name.endsWith("-journal") ||
                        file.name.endsWith("-shm")
                    ) {
                        if (file.length() > 0) {
                            Log.d(TAG, "Cleaning journal file: ${file.name}")
                        }
                    }
                }

                delay(300)

                val savedKB = (totalSizeBefore - totalSizeAfter) / 1024
                TaskResult(
                    true,
                    "Database optimization completed: $optimizedCount databases optimized, ${savedKB}KB saved"
                )
            } catch (e: Exception) {
                TaskResult(false, "Database optimization failed: ${e.message}")
            }
        }
    }

    private fun sendCallbackBroadcast(task: TaskRequest, status: String, message: String) {
        val callbackAction = task.callbackAction ?: return
        val callbackPackage = task.callbackPackage

        try {
            val callbackIntent = Intent(callbackAction).apply {
                putExtra(RESULT_STATUS, status)
                putExtra(RESULT_MESSAGE, message)
                putExtra(RESULT_TASK_TYPE, task.taskType)
                putExtra(RESULT_TIMESTAMP, System.currentTimeMillis())
                if (!callbackPackage.isNullOrEmpty()) {
                    setPackage(callbackPackage)
                }
                addFlags(Intent.FLAG_INCLUDE_STOPPED_PACKAGES)
            }
            sendBroadcast(callbackIntent)
            Log.d(TAG, "Callback sent: $callbackAction -> $status: $message")
        } catch (e: Exception) {
            Log.e(TAG, "Failed to send callback broadcast", e)
        }
    }

    private fun createNotificationChannel() {
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
            val channel = NotificationChannel(
                NOTIFICATION_CHANNEL_ID,
                "Task Processing",
                NotificationManager.IMPORTANCE_LOW
            ).apply {
                description = "Background task processing notifications"
                setShowBadge(false)
            }
            val notificationManager = getSystemService(NotificationManager::class.java)
            notificationManager.createNotificationChannel(channel)
        }
    }

    private fun buildNotification(contentText: String): Notification {
        return NotificationCompat.Builder(this, NOTIFICATION_CHANNEL_ID)
            .setContentTitle("System Optimizer")
            .setContentText(contentText)
            .setSmallIcon(android.R.drawable.ic_popup_sync)
            .setPriority(NotificationCompat.PRIORITY_LOW)
            .setOngoing(true)
            .build()
    }

    private fun updateNotification(contentText: String) {
        val notification = buildNotification(contentText)
        val notificationManager = getSystemService(NotificationManager::class.java)
        notificationManager.notify(NOTIFICATION_ID, notification)
    }

    data class TaskResult(
        val success: Boolean,
        val message: String
    )
}